    --muted:    #9a7a55;
    --dim:      #5a4030;
    --white:    #ffffff;
    --green:    #10b981;
    --purple:   #8b5cf6;
    --radius:   24px;
    --scroll:   0px;
  }

  *,*::before,*::after { box-sizing:border-box; margin:0; padding:0; }
  html { scroll-behavior:smooth; }
  body { font-family:'DM Sans',sans-serif; background:var(--bg); color:var(--text); overflow-x:hidden; }

  ::-webkit-scrollbar { width:5px; }
  ::-webkit-scrollbar-track { background:#0d0800; }
  ::-webkit-scrollbar-thumb { background:var(--amber); border-radius:10px; }

  /* ── ANIMATIONS ── */
  @keyframes fadeUp    { from{opacity:0;transform:translateY(30px)} to{opacity:1;transform:none} }
  @keyframes fadeLeft  { from{opacity:0;transform:translateX(50px)} to{opacity:1;transform:none} }
  @keyframes orbFloat  { 0%,100%{transform:translate(0,0) scale(1)} 33%{transform:translate(30px,-20px) scale(1.1)} 66%{transform:translate(-20px,15px) scale(0.95)} }
  @keyframes petFloat  { 0%,100%{transform:translate(-50%,-55%)} 50%{transform:translate(-50%,-60%)} }
  @keyframes floatPill { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-10px)} }
  @keyframes blink     { 0%,100%{opacity:1} 50%{opacity:0.2} }
  @keyframes shimmer   { 0%{background-position:-200% center} 100%{background-position:200% center} }
  @keyframes scaleIn   { from{opacity:0;transform:scale(0.93)} to{opacity:1;transform:scale(1)} }
  @keyframes slideInL  { from{opacity:0;transform:translateX(-30px)} to{opacity:1;transform:none} }
  @keyframes ripple    { to{transform:scale(4);opacity:0} }

  .reveal { opacity:0; transform:translateY(30px); transition:opacity 0.7s ease,transform 0.7s ease; }
  .reveal.visible { opacity:1; transform:none; }

  /* ── HERO ── */
  .ph-hero {
    min-height:100vh; position:relative; display:flex; align-items:center;
    overflow:hidden; background:var(--bg);
  }
  .ph-hero-bg {
    position:absolute; inset:0;
    background:linear-gradient(135deg,#0a0500 0%,#261000 45%,#130800 100%);
    transform:translateY(var(--scroll)); will-change:transform;
  }
  .ph-orb {
    position:absolute; border-radius:50%;
    filter:blur(80px); opacity:0.3; pointer-events:none;
  }
  .ph-orb-1 { width:600px;height:600px; background:radial-gradient(circle,#c8861a,transparent 70%); top:-150px;right:-100px; animation:orbFloat 8s ease-in-out infinite; }
  .ph-orb-2 { width:400px;height:400px; background:radial-gradient(circle,#4a7a4a,transparent 70%); bottom:-100px;left:-50px; animation:orbFloat 10s ease-in-out infinite reverse; }
  .ph-orb-3 { width:300px;height:300px; background:radial-gradient(circle,#8b4a2a,transparent 70%); top:40%;left:35%; animation:orbFloat 12s ease-in-out infinite 3s; }

  .ph-hero-content {
    position:relative; z-index:2; width:100%; max-width:1340px;
    margin:0 auto; padding:130px 60px 80px;
    display:grid; grid-template-columns:1fr 1fr; gap:70px; align-items:center;
  }
  .ph-hero-badge {
    display:inline-flex; align-items:center; gap:8px;
    background:rgba(200,134,26,0.12); border:1px solid rgba(200,134,26,0.35);
    border-radius:50px; padding:6px 18px;
    font-size:0.75rem; font-weight:700; letter-spacing:0.14em; text-transform:uppercase;
    color:var(--amber-l); margin-bottom:28px; animation:fadeUp 0.7s ease both;
  }
  .ph-dot { width:7px;height:7px; background:var(--amber-l); border-radius:50%; animation:blink 1.5s infinite; }

  .ph-hero-title {
    font-family:'Playfair Display',serif;
    font-size:clamp(3rem,5.5vw,6rem); line-height:1.0; font-weight:900;
    color:var(--white); margin-bottom:28px; animation:fadeUp 0.7s 0.1s ease both;
  }
  .ph-hero-title em {
    font-style:italic; color:var(--amber-l); position:relative; display:inline-block;
  }
  .ph-hero-title em::after {
    content:''; position:absolute; bottom:6px; left:0; right:0;
    height:3px; background:linear-gradient(90deg,var(--amber-l),transparent); border-radius:2px;
  }
  .ph-hero-sub {
    font-size:1.05rem; color:rgba(255,255,255,0.55); line-height:1.85;
    max-width:490px; margin-bottom:44px; font-weight:300; animation:fadeUp 0.7s 0.2s ease both;
  }
  .ph-hero-btns { display:flex;gap:16px; animation:fadeUp 0.7s 0.3s ease both; flex-wrap:wrap; }

  .ph-btn {
    padding:15px 34px; border-radius:50px;
    font-family:'DM Sans',sans-serif; font-size:0.95rem; font-weight:600;
