  .ph-btn-ghost { background:transparent; color:rgba(255,255,255,0.8); border:1.5px solid rgba(255,255,255,0.22) !important; }
  .ph-btn-ghost:hover { border-color:var(--amber-l) !important; color:var(--amber-l); text-decoration:none; }
  .ph-btn-outline { background:transparent; color:var(--amber); border:1.5px solid var(--amber) !important; }
  .ph-btn-outline:hover { background:var(--amber); color:white; text-decoration:none; }
  .ph-btn-white { background:white; color:var(--amber); box-shadow:0 8px 28px rgba(0,0,0,0.15); }
  .ph-btn-white:hover { transform:translateY(-3px); color:#8b5000; text-decoration:none; }
  .ph-btn-outline-white { background:transparent; color:white; border:1.5px solid rgba(255,255,255,0.45) !important; }
  .ph-btn-outline-white:hover { border-color:white !important; background:rgba(255,255,255,0.1); text-decoration:none; }

  .ph-hero-stats {
    display:flex; gap:44px; margin-top:52px;
    padding-top:36px; border-top:1px solid rgba(255,255,255,0.07);
    animation:fadeUp 0.7s 0.4s ease both;
  }
  .ph-stat-num { font-family:'Playfair Display',serif; font-size:2.1rem; font-weight:700; color:var(--amber-l); }
  .ph-stat-lbl { font-size:0.75rem; color:rgba(255,255,255,0.35); text-transform:uppercase; letter-spacing:0.1em; margin-top:2px; }

  /* ── HERO CARD SIDE ── */
  .ph-hero-visual { position:relative; display:flex; justify-content:center; animation:fadeLeft 0.9s 0.2s ease both; }
  .ph-main-card {
    width:380px; height:480px;
    background:linear-gradient(145deg,#261000,#4a2400);
    border-radius:40px; position:relative; overflow:hidden;
    box-shadow:0 40px 100px rgba(0,0,0,0.55), 0 0 0 1px rgba(200,134,26,0.14);
  }
  .ph-main-card::before { content:''; position:absolute; inset:0; background:linear-gradient(135deg,rgba(200,134,26,0.08),transparent 50%); }
  .ph-main-pet { position:absolute; top:50%; left:50%; transform:translate(-50%,-55%); font-size:9rem; animation:petFloat 4s ease-in-out infinite; filter:drop-shadow(0 20px 40px rgba(0,0,0,0.4)); line-height:1; }
  .ph-card-info { position:absolute; bottom:0; left:0; right:0; padding:28px; background:linear-gradient(to top,rgba(0,0,0,0.8),transparent); }
  .ph-card-badge-tag { display:inline-block; background:var(--amber); color:white; padding:4px 14px; border-radius:20px; font-size:0.7rem; font-weight:700; letter-spacing:0.06em; margin-bottom:8px; }
  .ph-card-pname { font-family:'Playfair Display',serif; font-size:1.5rem; font-weight:700; color:white; }
  .ph-card-pprice { color:rgba(255,255,255,0.55); font-size:0.9rem; margin-top:3px; }

  .ph-float-pill {
    position:absolute; background:rgba(255,255,255,0.95);
    backdrop-filter:blur(12px); border-radius:20px;
    padding:14px 20px; box-shadow:0 16px 50px rgba(0,0,0,0.2);
  }
  .ph-float-pill:nth-child(2) { top:-10px;right:-30px; animation:floatPill 4s ease-in-out infinite; }
