  /* ── TRUST BAR ── */
  .ph-trust { background:var(--surface); padding:32px 60px; display:flex; justify-content:center; gap:60px; flex-wrap:wrap; border-bottom:1px solid var(--border); }
  .ph-trust-item { display:flex; align-items:center; gap:14px; color:rgba(255,255,255,0.65); }
  .ph-trust-icon { font-size:1.7rem; width:50px;height:50px; background:var(--amber-xs); border:1px solid var(--border); border-radius:14px; display:flex; align-items:center; justify-content:center; flex-shrink:0; }
  .ph-trust-title { font-weight:600; color:white; font-size:0.9rem; }
  .ph-trust-sub   { font-size:0.75rem; color:rgba(255,255,255,0.38); margin-top:2px; }

